css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: #0a0800; font-family: -apple-system, sans-serif; display: flex; align-items: center; justify-content: center; color: white; }
.game { display: flex; flex-direction: column; align-items: center; gap: 12px; }
.header { display: flex; justify-content: space-between; align-items: center; width: 480px; }
h1 { font-size: 20px; font-weight: 900; }
.stat { font-size: 14px; color: #9ca3af; } .stat strong { color: #f97316; font-size: 18px; font-weight: 900; }
#canvas { border-radius: 12px; border: 2px solid rgba(249,115,22,0.3); display: block; box-shadow: 0 0 30px rgba(249,115,22,0.1); }
.overlay { position: absolute; width: 480px; height: 400px; background: rgba(10,8,0,0.85); border-radius: 12px; display: flex; align-items: center; justify-content: center; backdrop-filter: blur(8px); }
.ov-content { text-align: center; }
.ov-emoji { font-size: 56px; margin-bottom: 14px; }
.ov-content h2 { font-size: 28px; font-weight: 900; margin-bottom: 8px; }
.ov-content p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 24px; }
.ov-content button { padding: 14px 36px; border-radius: 14px; border: none; background: #f97316; color: white; font-size: 16px; font-weight: 800; cursor: pointer; }

