const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d');
const W = 480, H = 400;
const ROWS = 5, COLS = 10;
const BW = 40, BH = 14, BPAD = 4;
let ball, paddle, bricks, score, lives, running, animId;
const COLORS = ['#ef4444','#f97316','#eab308','#22c55e','#3b82f6'];
function makeBricks() {
  const b = [];
  for (let r=0;r<ROWS;r++) for (let c=0;c<COLS;c++) b.push({x:c*(BW+BPAD)+12, y:r*(BH+BPAD)+40, w:BW, h:BH, color:COLORS[r], alive:true});
  return b;
}
function startGame() {
  document.getElementById('overlay').style.display = 'none';
  ball = {x:W/2, y:H-60, vx:3, vy:-4, r:7};
  paddle = {x:W/2-40, y:H-20, w:80, h:10, speed:6};
  bricks = makeBricks();
  score = 0; lives = 3; running = true;
  document.getElementById('score').textContent = 0;
  document.getElementById('lives').textContent = 3;
  cancelAnimationFrame(animId);
  loop();
}
function loop() {
  ctx.fillStyle = '#0a0800';
  ctx.fillRect(0,0,W,H);
  bricks.forEach(b => { if (!b.alive) return; const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+b.h); g.addColorStop(0,b.color); g.addColorStop(1,b.color+'88'); ctx.fillStyle=g; ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h,4); ctx.fill(); });
  const bg=ctx.createLinearGradient(paddle.x,paddle.y,paddle.x+paddle.w,paddle.y); bg.addColorStop(0,'#f97316'); bg.addColorStop(1,'#ea580c');
  ctx.fillStyle=bg; ctx.beginPath(); ctx.roundRect(paddle.x,paddle.y,paddle.w,paddle.h,5); ctx.fill();
  const cg=ctx.createRadialGradient(ball.x,ball.y,1,ball.x,ball.y,ball.r); cg.addColorStop(0,'#fef3c7'); cg.addColorStop(1,'#f97316');
  ctx.fillStyle=cg; ctx.beginPath(); ctx.arc(ball.x,ball.y,ball.r,0,Math.PI*2); ctx.fill();
  ball.x+=ball.vx; ball.y+=ball.vy;
  if (ball.x<ball.r||ball.x>W-ball.r) ball.vx=-ball.vx;
  if (ball.y<ball.r) ball.vy=-ball.vy;
  if (ball.y+ball.r>paddle.y && ball.x>paddle.x && ball.x<paddle.x+paddle.w) {
    ball.vy=-Math.abs(ball.vy);
    ball.vx=(ball.x-paddle.x-paddle.w/2)/10;
  }
  if (ball.y>H) { lives--; document.getElementById('lives').textContent=lives; if (lives<=0) { running=false; document.getElementById('ov-emoji').textContent='💀'; document.getElementById('ov-title').textContent='Oyun Bitti!'; document.getElementById('ov-msg').textContent='Puanın: '+score; document.getElementById('overlay').style.display='flex'; return; } ball={x:W/2,y:H-60,vx:3,vy:-4,r:7}; }
  let all=true;
  bricks.forEach(b => { if (!b.alive) return; all=false; if (ball.x>b.x&&ball.x<b.x+b.w&&ball.y>b.y&&ball.y<b.y+b.h) { b.alive=false; ball.vy=-ball.vy; score+=10; document.getElementById('score').textContent=score; } });
  if (all) { document.getElementById('ov-emoji').textContent='🏆'; document.getElementById('ov-title').textContent='Kazandın!'; document.getElementById('ov-msg').textContent='Puan: '+score; document.getElementById('overlay').style.display='flex'; return; }
  if (keys.ArrowLeft && paddle.x>0) paddle.x-=paddle.speed;
  if (keys.ArrowRight && paddle.x+paddle.w<W) paddle.x+=paddle.speed;
  animId=requestAnimationFrame(loop);
}
const keys = {};
document.addEventListener('keydown', e => { keys[e.key]=true; });
document.addEventListener('keyup', e => { keys[e.key]=false; });
document.addEventListener('mousemove', e => { if (!running) return; const r=canvas.getBoundingClientRect(); paddle.x=e.clientX-r.left-paddle.w/2; paddle.x=Math.max(0,Math.min(W-paddle.w,paddle.x)); });
